    re.compile(r"from .* owned by (?P<assignee>[^,\.]+?)(?: and|,|\.|$)", re.IGNORECASE),
    re.compile(r"Application .* from .* owned by (?P<assignee>[^,\.]+?)(?: and|,|\.|$)", re.IGNORECASE),
]

